@startuml
skinparam backgroundColor #FFFFFF
skinparam defaultFontName "Arial"
skinparam defaultFontSize 14
skinparam classAttributeIconSize 0
skinparam classFontColor #000000
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #CCCCCC
skinparam classBorderThickness 1
skinparam classPadding 10
skinparam classMargin 10
skinparam classStereotypeFontColor #666666
skinparam classStereotypeFontSize 12
skinparam classStereotypeFontStyle italic
skinparam classStereotypeBackgroundColor #FFFFFF
skinparam classStereotypeBorderColor #999999
skinparam classStereotypeBorderThickness 1
skinparam classStereotypeBorderDashed true

package "Aggregate-Buch" {
    class "Buch" as Buch {
        <<root entity>>
    }

    class "AutorID" as AutorID {
        <<value>>
    }

    class "BuchID" as BuchID {
        <<value>>
    }

    class "Kapitel" as Kapitel {
        <<entity>>
    }

    class "KapitelID" as KapitelID {
        <<value>>
    }

    class "Status" as Status {
        <<value>>
    }
}

Buch o-- AutorID
Buch --> BuchID
Buch o-- Kapitel
Kapitel --> KapitelID
Kapitel --> Status
Buch --> Status

note right of Buch: root entity
note right of AutorID: value
note right of BuchID: value
note right of Kapitel: entity
note right of KapitelID: value
note right of Status: value

@enduml
